-- sql/functions/generate_username.sql
-- Generate a username from a rotating word list and permuted 2-digit suffix
CREATE OR REPLACE FUNCTION generate_username()
RETURNS TEXT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  a          CONSTANT INTEGER := 31; -- gcd(31, 101) = 1
  b          CONSTANT INTEGER := 23; -- gcd(23, 99) = 1
  word_count CONSTANT INTEGER := 101; -- gcd(101, 99) = 1
  max_tries  CONSTANT INTEGER := word_count * 99;
  n          BIGINT;
  word_index INTEGER;
  word       TEXT;
  num        TEXT;
  v_username TEXT;
  i          INTEGER;
BEGIN
  FOR i IN 1..max_tries LOOP
    n := nextval('public.username_counter');

    word_index := ((a * n) % word_count)::INTEGER;

    SELECT uw.word
    INTO word
    FROM public.username_words uw
    WHERE uw.pos = word_index;

    IF word IS NULL THEN
      RAISE EXCEPTION 'Missing word at index % (must be contiguous 0..%)',
        word_index, word_count - 1;
    END IF;

    -- Permuted 2-digit number in range 01..99
    num := LPAD((((b * n) % 99) + 1)::TEXT, 2, '0');
    v_username := word || num;

    IF NOT EXISTS (
      SELECT 1
      FROM public.users u
      WHERE u.username = v_username
    ) THEN
      RETURN v_username;
    END IF;
  END LOOP;

  RAISE EXCEPTION 'No unused username available in current cycle (word_count=%)', word_count;
END;
$$;

-- sql/functions/get_course_access_groups.sql
-- Return courses grouped by access level for the current session context
CREATE OR REPLACE FUNCTION get_course_access_groups()
RETURNS JSONB
LANGUAGE sql
STABLE
AS $$
WITH session_context AS (
  SELECT
    current_setting('app.user_role', true) AS user_role,
    current_setting('app.user_id', true)   AS user_id,
    current_setting('app.group_key', true) AS group_key
),
course_access AS (
  SELECT
    c.id,
    c.is_listed,
    c.is_public,
    (
      sc.user_role = 'admin'
      OR c.group_key = sc.group_key
      OR uc.user_id IS NOT NULL
    ) AS is_accessible
  FROM public.v_course_dto c
  CROSS JOIN session_context sc
  LEFT JOIN public.user_courses uc
    ON uc.course_id = c.id
   AND uc.user_id = sc.user_id
)
SELECT jsonb_build_object(
  'public', COALESCE(
    jsonb_agg(ca.id ORDER BY ca.id)
      FILTER (WHERE ca.is_listed AND ca.is_public),
    '[]'::jsonb
  ),
  'accessible', COALESCE(
    jsonb_agg(ca.id ORDER BY ca.id)
      FILTER (WHERE ca.is_listed AND NOT ca.is_public AND ca.is_accessible),
    '[]'::jsonb
  ),
  'restricted', COALESCE(
    jsonb_agg(ca.id ORDER BY ca.id)
      FILTER (WHERE ca.is_listed AND NOT ca.is_public AND NOT ca.is_accessible),
    '[]'::jsonb
  ),
  'hidden', COALESCE(
    jsonb_agg(ca.id ORDER BY ca.id)
      FILTER (WHERE NOT ca.is_listed),
    '[]'::jsonb
  )
)
FROM course_access ca;
$$;

-- sql/functions/get_progress_dto.sql
-- Return full course progress tree as JSONB
CREATE OR REPLACE FUNCTION get_progress_dto(p_course_id TEXT)
RETURNS JSONB
LANGUAGE sql
STABLE
AS $$
WITH course_base AS (
  SELECT
    c.course_id,
    c.slug
  FROM public.courses c
  WHERE c.course_id = p_course_id
),
topic_rows AS (
  SELECT
    ct.course_id,
    ct.topic_id,
    t.label AS topic_label,
    CONCAT(cb.slug, '/', t.href_slug) AS topic_href,
    ct.status AS topic_status,
    ct.display_order AS topic_order
  FROM public.course_topics ct
  JOIN public.topics t
    ON t.topic_id = ct.topic_id
  JOIN course_base cb
    ON cb.course_id = ct.course_id
),
chapter_rows AS (
  SELECT
    cc.course_id,
    cc.topic_id,
    cc.chapter_id,
    ch.label AS chapter_label,
    CONCAT(cb.slug, '/', t.href_slug, '/', ch.href_slug) AS chapter_href,
    cc.status AS chapter_status,
    cc.display_order AS chapter_order
  FROM public.course_chapters cc
  JOIN public.chapters ch
    ON ch.chapter_id = cc.chapter_id
  JOIN public.topics t
    ON t.topic_id = cc.topic_id
  JOIN course_base cb
    ON cb.course_id = cc.course_id
),
current_ids AS (
  SELECT
    COALESCE(
      (SELECT tr.topic_id FROM topic_rows tr WHERE tr.topic_status = 'current'),
      ''
    ) AS current_topic_id,
    COALESCE(
      (SELECT cr.chapter_id FROM chapter_rows cr WHERE cr.chapter_status = 'current'),
      ''
    ) AS current_chapter_id
),
worksheets_by_chapter AS (
  SELECT
    w.course_id,
    w.topic_id,
    w.chapter_id,
    jsonb_agg(
      jsonb_build_object(
        'worksheetId', w.worksheet_id,
        'label', w.label,
        'href', w.href,
        'worksheetFormat', w.worksheet_format
      )
      ORDER BY w.display_order, w.worksheet_id
    ) AS worksheets
  FROM public.v_worksheets_by_chapter w
  WHERE w.course_id = p_course_id
    AND w.is_hidden = false
  GROUP BY w.course_id, w.topic_id, w.chapter_id
),
chapters_with_worksheets AS (
  SELECT
    cr.course_id,
    cr.topic_id,
    cr.chapter_order,
    cr.chapter_id,
    jsonb_build_object(
      'chapterId', cr.chapter_id,
      'label', cr.chapter_label,
      'href', cr.chapter_href,
      'status', cr.chapter_status,
      'worksheets', COALESCE(wbc.worksheets, '[]'::jsonb)
    ) AS chapter_obj
  FROM chapter_rows cr
  LEFT JOIN worksheets_by_chapter wbc
    ON wbc.course_id = cr.course_id
   AND wbc.topic_id = cr.topic_id
   AND wbc.chapter_id = cr.chapter_id
),
chapters_by_topic AS (
  SELECT
    cww.course_id,
    cww.topic_id,
    jsonb_agg(cww.chapter_obj ORDER BY cww.chapter_order, cww.chapter_id) AS chapters
  FROM chapters_with_worksheets cww
  GROUP BY cww.course_id, cww.topic_id
),
topics_with_chapters AS (
  SELECT
    tr.course_id,
    tr.topic_order,
    tr.topic_id,
    jsonb_build_object(
      'topicId', tr.topic_id,
      'label', tr.topic_label,
      'href', tr.topic_href,
      'status', tr.topic_status,
      'chapters', COALESCE(cbt.chapters, '[]'::jsonb)
    ) AS topic_obj
  FROM topic_rows tr
  LEFT JOIN chapters_by_topic cbt
    ON cbt.course_id = tr.course_id
   AND cbt.topic_id = tr.topic_id
),
topics_agg AS (
  SELECT
    twc.course_id,
    jsonb_agg(twc.topic_obj ORDER BY twc.topic_order, twc.topic_id) AS topics
  FROM topics_with_chapters twc
  GROUP BY twc.course_id
)
SELECT jsonb_build_object(
  'currentTopicId', ci.current_topic_id,
  'currentChapterId', ci.current_chapter_id,
  'topics', COALESCE(ta.topics, '[]'::jsonb)
)
FROM current_ids ci
LEFT JOIN topics_agg ta
  ON TRUE;
$$;

-- sql/functions/get_quiz_broadcast_data.sql
-- Returns the full quiz session row plus aggregate counts needed for Ably broadcasts.
-- SECURITY DEFINER bypasses RLS so this can be called via anonSQL from student-triggered
-- code paths (submitQuizResponse, joinQuizSession) without the student's RLS restrictions
-- corrupting the participant and response counts sent to the admin channel.

CREATE OR REPLACE FUNCTION get_quiz_broadcast_data(p_session_id TEXT)
RETURNS TABLE (
  session_id       TEXT,
  course_id        TEXT,
  phase            TEXT,
  questions        JSONB,
  current_index    INTEGER,
  timer_seconds    INTEGER,
  timer_started_at TIMESTAMPTZ,
  updated_at       TIMESTAMPTZ,
  created_at       TIMESTAMPTZ,
  participant_count INTEGER,
  responses        JSON
)
SECURITY DEFINER
SET search_path = public
LANGUAGE sql
AS $$
  SELECT
    s.session_id,
    s.course_id,
    s.phase,
    s.questions,
    s.current_index,
    s.timer_seconds,
    s.timer_started_at,
    s.updated_at,
    s.created_at,
    (SELECT COUNT(*)::int FROM quiz_participants p WHERE p.session_id = s.session_id),
    COALESCE(
      (SELECT json_agg(r.selected)
       FROM quiz_responses r
       WHERE r.session_id = s.session_id
         AND r.question_index = s.current_index),
      '[]'::json
    )
  FROM quiz_sessions s
  WHERE s.session_id = p_session_id
$$;

-- sql/functions/get_session_user.sql
-- Session bootstrap lookup by user id
CREATE OR REPLACE FUNCTION get_session_user(p_user_id TEXT)
RETURNS TABLE (
  id         TEXT,
  role       TEXT,
  group_key  TEXT,
  course_ids TEXT[]
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
  WITH selected_user AS (
    SELECT
      u.id,
      u.role,
      u.group_key
    FROM public.users u
    WHERE u.id = p_user_id
  ),
  user_courses_agg AS (
    SELECT
      uc.user_id,
      array_agg(uc.course_id ORDER BY uc.course_id) AS course_ids
    FROM public.user_courses uc
    WHERE uc.user_id = p_user_id
    GROUP BY uc.user_id
  )
  SELECT
    su.id,
    su.role,
    su.group_key,
    COALESCE(uca.course_ids, ARRAY[]::TEXT[]) AS course_ids
  FROM selected_user su
  LEFT JOIN user_courses_agg uca
    ON uca.user_id = su.id;
$$;

-- sql/functions/get_user_for_login.sql
-- Login bootstrap lookup by username
DROP FUNCTION IF EXISTS get_user_for_login(TEXT);
CREATE FUNCTION get_user_for_login(p_username TEXT)
RETURNS TABLE (
  id          TEXT,
  role        TEXT,
  group_key   TEXT,
  username    TEXT,
  pin_hash    TEXT,
  enabled     BOOLEAN,
  course_ids  TEXT[]
)
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
  WITH selected_user AS (
    SELECT
      u.id,
      u.role,
      u.group_key,
      u.username,
      u.pin_hash,
      u.enabled
    FROM public.users u
    WHERE LOWER(u.username) = LOWER(p_username)
  ),
  user_courses_agg AS (
    SELECT
      uc.user_id,
      array_agg(uc.course_id ORDER BY uc.course_id) AS course_ids
    FROM public.user_courses uc
    JOIN selected_user su
      ON su.id = uc.user_id
    GROUP BY uc.user_id
  )
  SELECT
    su.id,
    su.role,
    su.group_key,
    su.username,
    su.pin_hash,
    su.enabled,
    COALESCE(uca.course_ids, ARRAY[]::TEXT[]) AS course_ids
  FROM selected_user su
  LEFT JOIN user_courses_agg uca
    ON uca.user_id = su.id;
$$;

