-- sql/functions/try_advance_quiz_phase.sql
-- Advances a quiz session from 'active' to 'reveal_dist' when all participants
-- have submitted their response for the current question.
-- Called by the student after submitting a response (via anonSQL / direct call).
-- SECURITY DEFINER bypasses RLS so students can trigger the phase update.

CREATE OR REPLACE FUNCTION try_advance_quiz_phase(
  p_session_id     TEXT,
  p_question_index INTEGER
)
RETURNS VOID
SECURITY DEFINER
SET search_path = public
LANGUAGE plpgsql
AS $$
DECLARE
  v_phase             TEXT;
  v_current_index     INTEGER;
  v_participant_count INTEGER;
  v_response_count    INTEGER;
BEGIN
  -- Only act when the session is actively accepting answers for the right question
  SELECT phase, current_index INTO v_phase, v_current_index
  FROM quiz_sessions
  WHERE session_id = p_session_id;

  IF v_phase IS DISTINCT FROM 'active' THEN
    RETURN;
  END IF;

  -- Ignore stale responses submitted for a previous question
  IF v_current_index IS DISTINCT FROM p_question_index THEN
    RETURN;
  END IF;

  -- Count how many students are in this session
  SELECT COUNT(*) INTO v_participant_count
  FROM quiz_participants
  WHERE session_id = p_session_id;

  -- Count responses for the current question
  SELECT COUNT(*) INTO v_response_count
  FROM quiz_responses
  WHERE session_id = p_session_id
    AND question_index = p_question_index;

  -- Auto-advance only when every participant has answered
  IF v_participant_count > 0 AND v_response_count >= v_participant_count THEN
    UPDATE quiz_sessions
    SET phase      = 'reveal_dist',
        updated_at = now()
    WHERE session_id = p_session_id
      AND phase = 'active'; -- guard against race condition
  END IF;
END;
$$;

-- sql/functions/update_course_progress.sql
-- Update course progress status for topics and chapters
CREATE OR REPLACE FUNCTION update_course_progress(
  p_course_id      TEXT,
  p_new_topic_id   TEXT,
  p_new_chapter_id TEXT
)
RETURNS VOID
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public, pg_temp
AS $$
DECLARE
  v_topic_order   INTEGER;
  v_chapter_order INTEGER;
BEGIN
  SELECT ct.display_order
  INTO v_topic_order
  FROM public.course_topics ct
  WHERE ct.course_id = p_course_id
    AND ct.topic_id = p_new_topic_id;

  IF v_topic_order IS NULL THEN
    RAISE EXCEPTION 'Topic % is not part of course %', p_new_topic_id, p_course_id
      USING ERRCODE = '22023';
  END IF;

  SELECT cc.display_order
  INTO v_chapter_order
  FROM public.course_chapters cc
  WHERE cc.course_id = p_course_id
    AND cc.topic_id = p_new_topic_id
    AND cc.chapter_id = p_new_chapter_id;

  IF v_chapter_order IS NULL THEN
    RAISE EXCEPTION 'Chapter % is not part of topic % in course %',
      p_new_chapter_id,
      p_new_topic_id,
      p_course_id
      USING ERRCODE = '22023';
  END IF;

  UPDATE public.course_topics
  SET status = 'locked'
  WHERE course_id = p_course_id AND status = 'current';

  UPDATE public.course_topics ct
  SET status = CASE
    WHEN ct.display_order < v_topic_order THEN 'finished'
    WHEN ct.topic_id = p_new_topic_id THEN 'current'
    WHEN ct.display_order = v_topic_order + 1 THEN 'planned'
    ELSE 'locked'
  END
  WHERE ct.course_id = p_course_id;

  UPDATE public.course_chapters
  SET status = 'locked'
  WHERE course_id = p_course_id AND status = 'current';

  UPDATE public.course_chapters cc
  SET status = CASE
    WHEN ct.display_order < v_topic_order THEN 'finished'
    WHEN cc.topic_id = p_new_topic_id AND cc.chapter_id = p_new_chapter_id THEN 'current'
    WHEN cc.topic_id = p_new_topic_id AND cc.display_order < v_chapter_order THEN 'finished'
    ELSE 'locked'
  END
  FROM public.course_topics ct
  WHERE ct.course_id = cc.course_id
    AND ct.topic_id = cc.topic_id
    AND cc.course_id = p_course_id;

  UPDATE public.courses c
  SET updated_at = NOW()
  WHERE c.course_id = p_course_id;
END;
$$;
